def _micro_strategy_dossier_to_nested(
    micro_strategy_dossier: MicroStrategyDossier,
) -> MicroStrategyDossierNested:
    """Convert flat MicroStrategyDossier to nested format."""
    attrs = MicroStrategyDossierAttributes()
    _populate_micro_strategy_dossier_attrs(attrs, micro_strategy_dossier)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        micro_strategy_dossier,
        _MICRO_STRATEGY_DOSSIER_REL_FIELDS,
        MicroStrategyDossierRelationshipAttributes,
    )
    return MicroStrategyDossierNested(
        guid=micro_strategy_dossier.guid,
        type_name=micro_strategy_dossier.type_name,
        status=micro_strategy_dossier.status,
        version=micro_strategy_dossier.version,
        create_time=micro_strategy_dossier.create_time,
        update_time=micro_strategy_dossier.update_time,
        created_by=micro_strategy_dossier.created_by,
        updated_by=micro_strategy_dossier.updated_by,
        classifications=micro_strategy_dossier.classifications,
        classification_names=micro_strategy_dossier.classification_names,
        meanings=micro_strategy_dossier.meanings,
        labels=micro_strategy_dossier.labels,
        business_attributes=micro_strategy_dossier.business_attributes,
        custom_attributes=micro_strategy_dossier.custom_attributes,
        pending_tasks=micro_strategy_dossier.pending_tasks,
        proxy=micro_strategy_dossier.proxy,
        is_incomplete=micro_strategy_dossier.is_incomplete,
        provenance_type=micro_strategy_dossier.provenance_type,
        home_id=micro_strategy_dossier.home_id,
        depth=micro_strategy_dossier.depth,
        immediate_upstream=micro_strategy_dossier.immediate_upstream,
        immediate_downstream=micro_strategy_dossier.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _micro_strategy_dossier_from_nested(
    nested: MicroStrategyDossierNested,
) -> MicroStrategyDossier:
    """Convert nested format to flat MicroStrategyDossier."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else MicroStrategyDossierAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _MICRO_STRATEGY_DOSSIER_REL_FIELDS,
        MicroStrategyDossierRelationshipAttributes,
    )
    return MicroStrategyDossier(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_micro_strategy_dossier_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _micro_strategy_dossier_to_nested_bytes(
    micro_strategy_dossier: MicroStrategyDossier, serde: Serde
) -> bytes:
    """Convert flat MicroStrategyDossier to nested JSON bytes."""
    return serde.encode(_micro_strategy_dossier_to_nested(micro_strategy_dossier))


def _micro_strategy_dossier_from_nested_bytes(
    data: bytes, serde: Serde
) -> MicroStrategyDossier:
    """Convert nested JSON bytes to flat MicroStrategyDossier."""
    nested = serde.decode(data, MicroStrategyDossierNested)
    return _micro_strategy_dossier_from_nested(nested)


